function calcularDesconto(preco, desconto) {
  return preco - desconto;
}

function montarMensagem(precoFinal) {
  return 'Preço final: R$ ' + precoFinal;
}

const precoComDesconto = calcularDesconto(100, 15);
const mensagem = montarMensagem(precoComDesconto);
console.log(mensagem);
